function generateHueSweepThemes() {
  const themes = [];
  for (let h = 0; h < 360; h += 10) {
    const label = `${h}°`;
    const id = `hue-${h}`;
    themes.push(
      makeTheme(
        `${id}-dark`,
        `Hue ${label} Dark`,
        id,
        "dark",
        "Spectrum",
        ["spectrum", "generated"],
        hsl(h, 70, 60),
        hsl(h, 10, 10),
        hsl(h, 8, 85),
        58,
        hsl((h + 120) % 360, 50, 45),
        hsl((h + 180) % 360, 55, 50),
        hsl((h + 60) % 360, 50, 55)
      ),
      makeTheme(
        `${id}-light`,
        `Hue ${label} Light`,
        id,
        "light",
        "Spectrum",
        ["spectrum", "generated"],
        hsl(h, 75, 42),
        hsl(h, 12, 97),
        hsl(h, 15, 15),
        40,
        hsl((h + 120) % 360, 50, 35),
        hsl((h + 180) % 360, 55, 42),
        hsl((h + 60) % 360, 50, 40)
      ),
      makeTheme(
        `${id}-vibrant`,
        `Hue ${label} Vibrant`,
        id,
        "dark",
        "Spectrum",
        ["spectrum", "vibrant", "generated"],
        hsl(h, 95, 55),
        hsl(h, 20, 6),
        hsl(h, 5, 90),
        65,
        hsl((h + 120) % 360, 60, 50),
        hsl((h + 180) % 360, 70, 45),
        hsl((h + 60) % 360, 65, 50)
      ),
      makeTheme(
        `${id}-matte`,
        `Hue ${label} Matte`,
        id,
        "dark",
        "Spectrum",
        ["spectrum", "matte", "generated"],
        hsl(h, 40, 55),
        hsl(h, 6, 14),
        hsl(h, 5, 78),
        48,
        hsl((h + 120) % 360, 35, 42),
        hsl((h + 180) % 360, 40, 45),
        hsl((h + 60) % 360, 35, 48)
      )
    );
  }
  return themes;
}
